const literacyData = [{"영역":"정보 활용","성취기준":"[D·L 01] 정보 검색을 위해 인터넷 등 다양한 디지털 환경을 목적에 맞게 활용할 수 있다.","평가요소":"검색 전략 및 도구 활용","잘함":"탐구 주제에 적합한 검색어와 플랫폼(포털, 앱 등)을 선택하여 필요한 정보를 정확히 찾아낼 수 있다.","보통":"제시된 정보 검색 도구를 활용하여 주제와 관련 있는 정보를 찾아낼 수 있다.","노력요함":"디지털 기기 조작이 미숙하여 교사의 반복적인 안내에도 디지털 환경 접속 및 기본 검색어 입력에 어려움이 있음."},{"영역":"콘텐츠 창작","성취기준":"[D·L 02] 사진, 그림, 동영상을 편집하여 창의적인 디지털 콘텐츠를 제작할 수 있다.","평가요소":"미디어 편집 및 제작","잘함":"다양한 편집 기능을 활용하여 시각 자료를 재구성하고, 의도가 담긴 창의적인 콘텐츠를 제작할 수 있다.","보통":"사진, 그림, 동영상 편집 도구를 사용하여 기본적인 형태의 콘텐츠를 제작할 수 있다.","노력요함":"디지털 콘텐츠의 기본 편집 도구 활용이 서툴러 사진이나 영상을 불러오고 수정하는 과정에서 도움이 필요함. "},{"영역":"콘텐츠 창작","성취기준":"[D·L 03] 디지털 콘텐츠를 검색·수집하여 목적에 맞는 발표 자료를 제작할 수 있다.","평가요소":"정보 재조직 및 시각화","잘함":"수집한 정보를 내용에 맞게 분류하고, 청중이 이해하기 쉬운 디지털 도구를 선택하여 자료를 구성할 수 있다.","보통":"검색한 디지털 콘텐츠를 활용하여 순서에 맞게 발표 자료를 제작할 수 있다.","노력요함":"학습 주제에 맞는 이미지나 텍스트를 검색하는 절차를 충분히 인지하지 못하며, 정보를 선택하여 수집하는 과정이 매우 제한적임."},{"영역":"디지털 세상 이해와 문제해결","성취기준":"[D·L 04] 일상 속 디지털 기술 및 서비스의 변화에 관심을 갖고 그 특징을 탐색한다.","평가요소":"기술 변화 인식 및 탐색","잘함":"우리 주변의 디지털 기술 변화를 민감하게 포착하고, 그 서비스가 삶에 주는 편리함과 특징을 설명할 수 있다.","보통":"일상에서 활용되는 디지털 기술 및 서비스를 찾아보고 그 용도에 대해 관심을 갖는다.","노력요함":"일상생활 속 디지털 기술과 서비스의 종류를 설명하는 데 어려움이 있음."},{"영역":"공유와 협업","성취기준":"[D·L 05] 자신의 생각과 의견을 디지털 에티켓을 준수하며 온라인상에 공유할 수 있다.","평가요소":"디지털 소통 및 예절","잘함":"사이버 언어 예절을 준수하며 자신의 의견을 논리적으로 구성하여 인터넷이나 SNS에 공유할 수 있다.","보통":"자신의 생각과 의견을 인터넷, SNS 등의 매체에 글이나 그림으로 게시할 수 있다.","노력요함":"온라인 플랫폼에 의견을 게시하거나 공유하는 절차를 이해하지 못하여, 교사의 전적인 도움 없이는 활동 참여가 어려움."},{"영역":"공유와 협업","성취기준":"[D·L 06] 디지털 협업 도구를 활용하여 공동의 과제를 해결하는 활동에 참여할 수 있다.","평가요소":"디지털 협력 및 상호작용","잘함":"협업 도구의 기능을 숙지하여 모둠원과 실시간으로 소통하며 맡은 역할을 적극적으로 수행할 수 있다.","보통":"디지털 기술을 활용하여 다른 사람과 정보를 주고받으며 공동 작업에 참여할 수 있다.","노력요함":"디지털 협업 과정에서 지켜야 할 약속이나 예절에 대한 인식이 부족하며, 공동 작업 시 타인과의 상호작용이 원활하지 않음."},{"영역":"디지털 세상 이해와 문제해결","성취기준":"[D·L 07] 디지털 도구를 활용하여 생활 속 문제를 해결하는 방안을 고안할 수 있다.","평가요소":"디지털 문제해결력","잘함":"생활 속 불편함을 개선하기 위해 디지털 도구의 기능을 창의적으로 조합하여 해결 방안을 제시할 수 있다.","보통":"제시된 상황 속 문제를 해결하기 위해 적절한 디지털 도구를 선택하고 활용할 수 있다.","노력요함":"생활 속 문제를 디지털 기술로 해결할 수 있다는 점을 잘 이해하지 못하며, 관련 사례를 발견하거나 열거하는 데 어려움을 보임."},{"영역":"디지털 안전과 예방","성취기준":"[D·L 08] 디지털 저작물의 출처를 밝히고 저작권 보호를 실천하는 태도를 갖는다.","평가요소":"저작권 준수 및 윤리","잘함":"자료 활용 시 정해진 형식에 따라 출처를 정확히 표기하며, 타인의 저작물을 보호하려는 태도를 실천한다.","보통":"다른 사람의 사진, 이미지, 글을 사용할 때 그 출처가 어디인지 명확히 밝힌다.","노력요함":"저작권과 개인정보 보호의 필요성에 대한 인식이 낮으며, 이를 보호해야 하는 이유를 단순한 차원에서도 설명하기 힘들어함."},{"영역":"디지털 안전과 예방","성취기준":"[D·L 09] 사이버 폭력의 위험성을 인지하고 이를 예방하기 위한 수칙을 실천한다.","평가요소":"디지털 안전 및 예방","잘함":"사이버 폭력의 유형과 대처법을 숙지하여 일상에서 예방 수칙을 적극적으로 실천하고 전파할 수 있다.","보통":"디지털 공간에서 발생할 수 있는 사이버 폭력의 사례를 알고, 예방하려는 태도를 보인다.","노력요함":"사이버 폭력의 다양한 형태와 위험성을 명확히 구분하지 못하며, 특정 행동이 폭력이 될 수 있음을 식별하는 능력이 부족함."},{"영역":"디지털 메타인지","성취기준":"[D·L 10] 학습 목적에 적합한 디지털 도구와 환경을 스스로 선택하고, 학습 과정과 결과를 점검하며 자기 주도적으로 조절할 수 있다.","평가요소":"학습목적별 도구선택, 자기 모니터링","잘함":"[상] 과제 해결에 가장 효과적인 디지털 도구와 환경을 스스로 비교하여 선택하고, 학습 과정 중 자신의 집중도와 진척 상황을 주기적으로 점검하며 최선의 결과를 얻기 위해 학습 방법을 능동적으로 수정함.","보통":"제시된 학습 목적에 맞는 디지털 도구를 선택하여 활용할 수 있으며, 학습이 끝난 후 자신의 학습 과정과 결과가 계획에 부합하는지 확인하고 부족한 점을 찾아낼 수 있음.","노력요함":"지정된 도구 활용에 소극적이며, 자신의 학습 결과물에 대한 이해가 부족함. "}]
;

class DataService {
  static _getDataByGrade(grade) {
    if (grade === '1~2학년군') return curriculumData_1_2;
    if (grade === '3~4학년군') return curriculumData_3_4;
    return curriculumData_5_6;
  }

  static async getSubjects(grade) {
    const data = this._getDataByGrade(grade);
    return [...new Set(data.map(item => item['교과']))].filter(Boolean);
  }

  static async getCurriculumStandards(grade, subject) {
    const data = this._getDataByGrade(grade);
    return data.filter(item => item['교과'] === subject);
  }

  static async getLiteracyAreas() {
    return [...new Set(literacyData.map(item => item['영역']))].filter(item => item && item.trim() !== '');
  }

  static async getLiteracyStandards(area) {
    return literacyData.filter(item => item['영역'] === area);
  }
}
